mapper.update:
UPDATE product
name = #{name}, category_id = #{categoryId}, description = #{description}, price = #{price}, stock_quantity = #{stockQuantity}, min_stock_level = #{minStockLevel}, supplier = #{supplier}, status = #{status}, stock_value = #{stockValue}, in_time = #{inTime}, out_time = #{outTime}, updated_time = CURRENT_TIMESTAMP
WHERE id = #{id}

mapper.select:
SELECT p.*, c.name as category_name, c.description as category_description, CASE WHEN c.level = 1 THEN c.name WHEN c.level = 2 THEN CONCAT(p1.name, '-', c.name) WHEN c.level = 3 THEN CONCAT(p1.name, '-', p2.name, '-', c.name) END as category_full_path FROM product p LEFT JOIN category c ON p.category_id = c.id LEFT JOIN category p2 ON c.parent_id = p2.id LEFT JOIN category p1 ON p2.parent_id = p1.id
AND p.name LIKE CONCAT('%', #{name}, '%')
AND p.category_id = #{categoryId}
AND p.supplier LIKE CONCAT('%', #{supplier}, '%')
AND p.stock_quantity >= #{stockQuantity}
ORDER BY p.id ASC
